const items = $input.all();
const segmentedLeads = {
  technology: [],
  finance: [],
  healthcare: [],
  retail: [],
  other: []
};

for (const item of items) {
  const industry = item.json.industry || 'other';
  const segment = segmentedLeads[industry.toLowerCase()] || segmentedLeads.other;

  segment.push({
    json: {
      ...item.json,
      segment: industry,
      personalization: {
        greeting: `${item.json.first_name || 'there'}`,
        interests_list: item.json.interests ? item.json.interests.split(',').map(i => i.trim()) : [],
        language: item.json.preferred_language || 'en',
        industry_specific: true
      }
    }
  });
}

// Flatten all segments into a single array
const output = [];
for (const segment in segmentedLeads) {
  output.push(...segmentedLeads[segment]);
}

return output;

const item = $input.item.json;
const interests = item.personalization.interests_list;
const industry = item.segment.toLowerCase();

// Email template selection logic
let templateId = 'general_acquisition';
let subject = '';
let preheader = '';

// Industry-specific templates
if (industry === 'technology') {
  templateId = 'tech_acquisition';
  subject = `${item.personalization.greeting}, Transform Your Tech Stack`;
  preheader = 'Innovative solutions for modern tech companies';
} else if (industry === 'finance') {
  templateId = 'finance_acquisition';
  subject = `${item.personalization.greeting}, Streamline Your Financial Operations`;
  preheader = 'Secure and compliant solutions for financial services';
} else if (industry === 'healthcare') {
  templateId = 'healthcare_acquisition';
  subject = `${item.personalization.greeting}, Improve Patient Care with Our Solutions`;
  preheader = 'HIPAA-compliant tools for healthcare providers';
} else if (industry === 'retail') {
  templateId = 'retail_acquisition';
  subject = `${item.personalization.greeting}, Boost Your Retail Sales`;
  preheader = 'Customer engagement tools for retail success';
} else {
  subject = `${item.personalization.greeting}, Discover Solutions for Your Business`;
  preheader = 'Tailored solutions for your industry';
}

// Interest-based content customization
const contentBlocks = [];
if (interests.includes('automation')) {
  contentBlocks.push('automation_benefits');
}
if (interests.includes('analytics')) {
  contentBlocks.push('analytics_showcase');
}
if (interests.includes('integration')) {
  contentBlocks.push('integration_features');
}
if (interests.includes('security')) {
  contentBlocks.push('security_highlights');
}

// Default content if no specific interests
if (contentBlocks.length === 0) {
  contentBlocks.push('general_benefits', 'customer_testimonials');
}

return {
  json: {
    ...item,
    email_config: {
      template_id: templateId,
      subject: subject,
      preheader: preheader,
      content_blocks: contentBlocks,
      personalization_tokens: {
        first_name: item.first_name,
        company_size: item.company_size,
        job_role: item.job_role,
        interests: interests.join(', '),
        industry: item.segment
      }
    }
  }
};

const item = $input.item.json;
const config = item.email_config;
const tokens = config.personalization_tokens;

// Build HTML email content
let htmlContent = `
<!DOCTYPE html>
<html lang="${item.personalization.language}">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>${config.subject}</title>
  <style>
    body { font-family: Arial, sans-serif; line-height: 1.6; color: #333; }
    .container { max-width: 600px; margin: 0 auto; padding: 20px; }
    .header { background: linear-gradient(135deg, #667eea 0%, #764ba2 100%); color: white; padding: 30px; text-align: center; border-radius: 10px 10px 0 0; }
    .content { background: #ffffff; padding: 30px; border: 1px solid #e0e0e0; }
    .cta-button { display: inline-block; background: #667eea; color: white; padding: 12px 30px; text-decoration: none; border-radius: 5px; margin: 20px 0; }
    .footer { background: #f5f5f5; padding: 20px; text-align: center; font-size: 12px; color: #666; border-radius: 0 0 10px 10px; }
    .benefit-box { background: #f8f9fa; padding: 15px; margin: 15px 0; border-left: 4px solid #667eea; }
  </style>
</head>
<body>
  <div class="container">
    <div class="header">
      <h1>Welcome, ${tokens.first_name}!</h1>
      <p>${config.preheader}</p>
    </div>
    <div class="content">
      <p>Hi ${tokens.first_name},</p>
      <p>We noticed you're interested in <strong>${tokens.interests}</strong> for your ${tokens.industry} business. We have something special for you!</p>
`;

// Add content blocks based on interests
if (config.content_blocks.includes('automation_benefits')) {
  htmlContent += `
      <div class="benefit-box">
        <h3>🚀 Automation That Works for You</h3>
        <p>Save 10+ hours per week with our intelligent automation tools designed specifically for ${tokens.industry} professionals.</p>
      </div>
`;
}

if (config.content_blocks.includes('analytics_showcase')) {
  htmlContent += `
      <div class="benefit-box">
        <h3>📊 Data-Driven Insights</h3>
        <p>Make smarter decisions with real-time analytics and customizable dashboards tailored to your needs.</p>
      </div>
`;
}

if (config.content_blocks.includes('integration_features')) {
  htmlContent += `
      <div class="benefit-box">
        <h3>🔗 Seamless Integrations</h3>
        <p>Connect with 100+ tools you already use. No complex setup required.</p>
      </div>
`;
}

if (config.content_blocks.includes('security_highlights')) {
  htmlContent += `
      <div class="benefit-box">
        <h3>🔒 Enterprise-Grade Security</h3>
        <p>Your data is protected with bank-level encryption and compliance certifications.</p>
      </div>
`;
}

if (config.content_blocks.includes('general_benefits')) {
  htmlContent += `
      <div class="benefit-box">
        <h3>✨ Why Choose Us?</h3>
        <ul>
          <li>Easy to use, no technical expertise required</li>
          <li>24/7 customer support</li>
          <li>Free trial with no credit card needed</li>
          <li>ROI guaranteed within 90 days</li>
        </ul>
      </div>
`;
}

if (config.content_blocks.includes('customer_testimonials')) {
  htmlContent += `
      <div class="benefit-box">
        <h3>💬 What Our Customers Say</h3>
        <p><em>"This solution transformed how we work. Highly recommended for ${tokens.industry} companies!"</em></p>
        <p><strong>- Sarah M., ${tokens.job_role}</strong></p>
      </div>
`;
}

htmlContent += `
      <p style="text-align: center;">
        <a href="https://yourcompany.com/signup?ref=email&industry=${tokens.industry}&utm_source=n8n&utm_medium=email&utm_campaign=acquisition" class="cta-button">Start Your Free Trial</a>
      </p>
      <p>No credit card required. Cancel anytime.</p>
      <p>Best regards,<br>Your Customer Success Team</p>
    </div>
    <div class="footer">
      <p>You're receiving this email because you expressed interest in our services.</p>
      <p><a href="https://yourcompany.com/unsubscribe?email=${item.email}">Unsubscribe</a> | <a href="https://yourcompany.com/preferences?email=${item.email}">Update Preferences</a></p>
      <p>© 2026 Your Company. All rights reserved.</p>
    </div>
  </div>
</body>
</html>
`;

// Plain text version
const textContent = `
Hi ${tokens.first_name},

We noticed you're interested in ${tokens.interests} for your ${tokens.industry} business.

Here's what we can offer you:
${config.content_blocks.map(block => `- ${block.replace('_', ' ')}`).join('\n')}

Start your free trial today: https://yourcompany.com/signup?ref=email&industry=${tokens.industry}

No credit card required. Cancel anytime.

Best regards,
Your Customer Success Team

---
Unsubscribe: https://yourcompany.com/unsubscribe?email=${item.email}
`;

return {
  json: {
    to: item.email,
    subject: config.subject,
    html: htmlContent,
    text: textContent,
    from: 'hello@yourcompany.com',
    fromName: 'Your Company Team',
    replyTo: 'support@yourcompany.com',
    user_id: item.id,
    campaign: 'customer_acquisition',
    segment: item.segment,
    template_id: config.template_id
  }
};

