parameters.jsCode:
const allItems = $input.all();

const summary = {
  total_processed: allItems.length,
  successful: allItems.filter(item => !item.json.error).length,
  failed: allItems.filter(item => item.json.error).length,
  segments: {},
  timestamp: new Date().toISOString()
};

// Count by segment
for (const item of allItems) {
  const segment = item.json.segment || 'unknown';
  if (!summary.segments[segment]) {
    summary.segments[segment] = 0;
  }
  summary.segments[segment]++;
}

return [{ json: summary }];

